body:
Hello,

I am running a very simple Verilog testbench using `Verilator 5.006 2023-01-22 rev (Debian 5.006-3)` and for some reason the resulting waveform doesn't show all changes of one of the signals, even though when I print the value before every change, changing values are printed.

The testbench code looks as below. The DUT can be found [here](https://github.com/GabbedT/Arithmetic-Circuits/blob/main/Integer/Dividers/non_restoring_divider.sv).
```SystemVerilog
module tb;

    localparam DATA_WIDTH = 8;

    logic                    clk_i;
    logic                    clk_en_i;
    logic                    rst_n_i;
    logic [DATA_WIDTH - 1:0] dividend_i;
    logic [DATA_WIDTH - 1:0] divisor_i;
    logic                    data_valid_i;

    logic [DATA_WIDTH - 1:0] quotient_o;
    logic [DATA_WIDTH - 1:0] remainder_o;
    logic                    divide_by_zero_o;
    logic                    data_valid_o;
    logic                    idle_o;

    always #10 clk_i = ~clk_i;

    logic [DATA_WIDTH - 1:0] dividend_reg;

non_restoring_divider #(
    .DATA_WIDTH (DATA_WIDTH)
) dut (
    .clk_i             (clk_i),
    .clk_en_i          (clk_en_i),
    .rst_n_i           (rst_n_i),
    .dividend_i        (dividend_i),
    .divisor_i         (divisor_i),
    .data_valid_i      (data_valid_i),

    .quotient_o        (quotient_o),
    .remainder_o       (remainder_o),
    .divide_by_zero_o  (divide_by_zero_o),
    .data_valid_o      (data_valid_o),
    .idle_o            (idle_o)
);

initial begin

    clk_i = 0;
    clk_en_i = 1;
    rst_n_i = 0;
    data_valid_i = 0;
    @(posedge clk_i);
    @(posedge clk_i);
    rst_n_i = 1;
    @(posedge clk_i);

    // stimulus
    for (int i = 0; i < 10; i++) begin
        while (idle_o == 0) begin
            $display("%t ns: waiting dividend_i %x divisor_i %x", $time, dividend_i, divisor_i);
            dividend_i = $random;
            divisor_i = divisor_i + 1;
            @(posedge clk_i);
        end
        $display("%t ns: Iteration %0d", $time, i);

        dividend_i = $random;
        divisor_i = $random;
        data_valid_i = 1;
        @(posedge clk_i);
        data_valid_i = 0;
    end

    #200 $finish;
end

  // Debug signal
always_ff @(posedge clk_i) begin
    dividend_reg <= dividend_i;
end

  // Simulator dependent system tasks that can be used to
  // dump simulation waves.
initial begin
    $dumpfile("dump.fst");
    $dumpvars;
end
endmodule
```

I verilate the code using
`verilator --Wno-fatal --binary --main --trace-fst tb.sv non_restoring_divider.sv`
then run the testbench, which outputs this:
